<?php require_once __DIR__.'/includes/bootstrap.php'; if($_SERVER['REQUEST_METHOD']==='POST'){ $u=$pdo->prepare('UPDATE medicines SET stock=? WHERE id=?');$u->execute([(int)$_POST['stock'],(int)$_POST['id']]);} $m=$pdo->query('SELECT * FROM medicines ORDER BY name')->fetchAll(); include __DIR__.'/includes/header.php'; ?><main class='page-shell'><h1>Manage Stocks</h1><?php foreach($m as $r): ?><form method='post' class='cart-item'><b><?= e($r['name'])?></b> <input name='stock' value='<?= (int)$r['stock']?>'><input type='hidden' name='id' value='<?= $r['id']?>'><button class='btn'>Save</button></form><?php endforeach; ?></main><?php include __DIR__.'/includes/footer.php'; ?>